def min_subarray_len(target: int, nums: list[int]) -> int:
    best = len(nums) + 1
    for left in range(len(nums)):
        current = 0
        for right in range(left, len(nums)):
            current += nums[right]
            if current >= target:
                best = min(best, right - left + 1)
                break
    return 0 if best == len(nums) + 1 else best
